const source = $json.body && typeof $json.body === 'object' ? $json.body : $json;

const asString = (value) => (value ?? '').toString().trim();
const asArray = (value) => {
  if (Array.isArray(value)) return value;
  if (typeof value === 'string') return value.split('\n').map((item) => item.trim()).filter(Boolean);
  return [];
};

const normalizeMaterials = (value) => {
  if (Array.isArray(value)) {
    return value
      .map((item) => ({
        title: asString(item.title),
        format: asString(item.format),
        summary: asString(item.summary),
        column_angle: asString(item.column_angle || item.angle || item.reason),
      }))
      .filter((item) => item.title || item.summary || item.column_angle);
  }

  if (typeof value === 'string') {
    return value
      .split('\n')
      .map((line) => line.trim())
      .filter(Boolean)
      .map((line) => {
        const [title, format, summary, column_angle] = line.replace(/^-+\s*/, '').split('|').map((part) => part.trim());
        return { title, format, summary, column_angle };
      })
      .filter((item) => item.title || item.summary || item.column_angle);
  }

  return [];
};

const brief = {
  session_id: asString(source.session_id || source.sessionId),
  user_id: asString(source.user_id || source.userId),
  issue_number: asString(source.issue_number || source.issueNumber),
  issue_theme: asString(source.issue_theme || source.issueTheme),
  issue_core_idea: asString(source.issue_core_idea || source.coreIdea),
  issue_context: asString(source.issue_context || source.context),
  issue_theses: asArray(source.issue_theses || source.theses),
  issue_materials: normalizeMaterials(source.issue_materials || source.materials),
  target_length: asString(source.target_length || source.targetLength || 'standard'),
  personal_tone_level: asString(source.personal_tone_level || source.personalToneLevel || 'medium'),
  editor_notes: asString(source.editor_notes || source.editorNotes),
  source_transcript: asString(source.source_transcript || source.sourceTranscript),
  callback_url: asString(source.callback_url || source.callbackUrl),
  callback_secret: asString(source.callback_secret || source.callbackSecret),
};

const tovProfile = asString(source.tov_profile || source.tovProfile);
const promptRules = asString(source.prompt_rules || source.promptRules);

const missing = [];
if (!brief.issue_theme) missing.push('issue_theme');
if (!brief.issue_core_idea && !brief.issue_context) missing.push('issue_core_idea or issue_context');

if (missing.length) {
  throw new Error(`Missing required editorial column fields: ${missing.join(', ')}`);
}

return [{
  json: {
    brief,
    tov_profile: tovProfile,
    prompt_rules: promptRules,
  },
}];

const tovProfile = ($json.tov_profile || '').trim();
const promptRules = ($json.prompt_rules || '').trim();

if (!tovProfile) {
  throw new Error('Missing tov_profile in webhook payload');
}

if (!promptRules) {
  throw new Error('Missing prompt_rules in webhook payload');
}

return [{
  json: {
    ...$json,
    tovProfile,
    promptRules,
  },
}];

const previous = $('Build Classification Request').first().json;
const response = $input.first().json;

const extractText = (payload) => {
  if (!payload) return '';

  if (typeof payload.output_text === 'string') return payload.output_text.trim();
  if (typeof payload.text === 'string') return payload.text.trim();
  if (typeof payload.output === 'string') return payload.output.trim();
  if (typeof payload.content === 'string') return payload.content.trim();
  if (typeof payload.response === 'string') return payload.response.trim();

  if (typeof payload.message === 'string') return payload.message.trim();

  if (payload.message?.content) {
    if (typeof payload.message.content === 'string') return payload.message.content.trim();

    if (Array.isArray(payload.message.content)) {
      return payload.message.content
        .map((entry) => entry.text || entry.output_text || '')
        .filter(Boolean)
        .join('\n')
        .trim();
    }
  }

  if (Array.isArray(payload.output)) {
    const chunks = payload.output
      .flatMap((entry) => Array.isArray(entry.content) ? entry.content : [])
      .map((entry) => entry.text || entry.output_text || '')
      .filter(Boolean);

    if (chunks.length) return chunks.join('\n').trim();
  }

  if (Array.isArray(payload.choices)) {
    const content = payload.choices[0]?.message?.content;
    if (typeof content === 'string') return content.trim();
  }

  if (payload.data && typeof payload.data === 'object') {
    return extractText(payload.data);
  }

  return '';
};

const safeParse = (text) => {
  try {
    return JSON.parse(
      text
        .replace(/^```json\s*/i, '')
        .replace(/^```\s*/i, '')
        .replace(/```$/i, '')
        .trim(),
    );
  } catch (error) {
    return {
      column_type: 'values',
      confidence: 0.3,
      reason: 'Fallback: не удалось распарсить классификацию.',
      secondary_type: '',
    };
  }
};

const classification = safeParse(extractText(response));

return [
  {
    json: {
      ...previous,
      classification: {
        column_type: classification.column_type || 'values',
        confidence: Number(classification.confidence || 0.3),
        reason: classification.reason || '',
        secondary_type: classification.secondary_type || '',
      },
    },
  },
];

const { brief, tovProfile, promptRules, classification } = $json;

const lengthMap = {
  short: 'примерно 220-280 слов',
  standard: 'примерно 320-430 слов',
  long: 'примерно 480-650 слов',
};

const typeAccents = {
  cultural: 'Сделай акцент на культурной теме, ремесле, художественной практике, преемственности и историко-культурной памяти.',
  city: 'Сделай акцент на городской среде, памяти места, маршрутах, пространстве, образе города и человеческом опыте внутри него.',
  values: 'Сделай акцент на смысле, преемственности, внутреннем выборе, достоинстве, мере, уважении, созидании.',
  personal: 'Допусти немного больше личной интонации, но без исповедальности и без слишком частого "я".',
  ecology: 'Сделай акцент на природе, устойчивости, ресурсах, бережности, зеленой энергетике и ответственности.',
  event: 'Сделай акцент на конкретном событии или поводе как на знаке времени, но не превращай текст в новостной анонс.',
};

const facts = (brief.issue_context || '').trim();
const theses = Array.isArray(brief.issue_theses) ? brief.issue_theses : [];
const materials = brief.issue_materials?.length
  ? brief.issue_materials
      .map(
        (item, index) =>
          `${index + 1}. ${item.title || 'Без названия'} | ${item.format || 'формат не указан'} | ${item.summary || 'краткое описание не указано'} | ${item.column_angle || 'связать с темой номера'}`,
      )
      .join('\n')
  : 'Материалы не указаны. Не выдумывай конкретные публикации.';

const userPrompt = `Тема номера:
${brief.issue_theme || ''}

Главная мысль колонки:
${brief.issue_core_idea || ''}

Факты, которые нужно использовать:
${facts || 'не указаны'}

Дополнительные тезисы:
${theses.length ? theses.map((item) => `- ${item}`).join('\n') : '- не указаны'}

Материалы номера:
${materials}

Желаемая длина:
${lengthMap[brief.target_length] || lengthMap.standard}

Степень личной интонации:
${brief.personal_tone_level || 'medium'}

Дополнительные пожелания редактора:
${brief.editor_notes || 'нет'}

Если есть расшифровка голосового брифа, учитывай ее как дополнительный контекст, но не цитируй механически:
${brief.source_transcript || 'нет'}

Внутренний тип колонки:
${classification.column_type || 'values'}

Вторичный тип:
${classification.secondary_type || 'нет'}

Акцент типа:
${typeAccents[classification.column_type] || typeAccents.values}

Задача:
Напиши колонку главного редактора в tone of voice Лейлы Алиевой.

Что особенно важно:
- текст должен быть цельным, спокойным, ясным и собранным
- не делай текст слишком гладким, слишком литературным или слишком идеально отполированным
- не подменяй конкретику красивыми обобщениями
- если в фактах есть выразительные, частные, запоминающиеся детали, постарайся сохранить хотя бы часть из них
- не сокращай живую фактуру до сухого обобщения, если она делает текст человечнее и точнее
- лучше сохранить 1-2 характерные детали, чем полностью выгладить текст
- используй факты как смысловые опоры, а не как список
- материалы номера должны быть встроены органично, а не перечислены подряд
- не превращай колонку в анонс выпуска
- не выдумывай новые факты, детали или материалы
- если материалов мало и они важны, лучше использовать все
- если фактов много, выбери самые сильные и выразительные, но не теряй центральные
- в тексте должна остаться главная мысль номера, а не только атмосферный тон

На что обратить особое внимание stylistically:
- мысль глубокая, но выражена простыми словами
- автор не убеждает, а спокойно констатирует
- текст должен читаться плавно; избегай серии коротких, обрывистых предложений подряд
- абзац должен развиваться как единая смысловая волна, а не как набор аккуратных тезисов
- можно строить фразы средней длины, если это помогает течению мысли
- не злоупотребляй абстрактными словами вроде "эпоха", "судьба", "истина", "гармония", если они не подкреплены конкретикой
- избегай пафоса, восторженности и лишней красивости
- не делай текст стерильно-редакторским
- избегай безопасных редакторских прокладок вроде "важная для нас мысль", "одна простая вещь", "ясное напоминание", если можно сказать точнее и прямее
- не строй текст из универсальных фраз, которые можно вставить почти в любой номер
- хотя бы в одном месте дай не только тезис, но и живую, конкретную опору или деталь
- допустима легкая шероховатость живого текста, если она звучит естественно

Финал:
Собери колонку в ясную, сильную и спокойную мысль. Финал должен ощущаться человеческим и точным, а не просто красивым. Не закрывай текст слишком шаблонно или слишком назидательно.`;

const request = {
  model: $env.OPENAI_TEXT_MODEL || 'gpt-5.1',
  store: true,
  temperature: 0.55,
  max_output_tokens: 3500,
  input: `${tovProfile}\n\n${promptRules}\n\n${userPrompt}`,
};

return [{ json: { ...$json, userPrompt, openaiRequest: JSON.stringify(request) } }];

