const draft = extractText(response);
if (!draft) throw new Error('OpenAI draft response is empty');

const reviewPrompt = `Ты редактор выпуска журнала "Баку". Проверь и мягко улучши черновик колонки главного редактора.

Цель: сохранить tone of voice Лейлы Алиевой и сделать текст более цельным.

Проверь:
- не выглядит ли текст списком анонсов
- не слишком ли он общий
- не потерян ли теплый, светлый, литературный тон
- не слишком ли много материалов упомянуто
- есть ли органичный финал

Если текст уже хорош, оставь его почти без изменений. Не добавляй комментарии. Верни только финальный текст колонки без markdown, заголовков и пояснений.

ToV:
${previous.tovProfile}

Исходный бриф:
${previous.userPrompt}

Черновик:
${draft}`;

const request = {
  model: $env.OPENAI_TEXT_MODEL || 'gpt-5.1',
  store: true,
  temperature: 0.25,
  max_output_tokens: 3500,
  input: reviewPrompt,
};

return [{ json: { ...previous, draft, openaiRequest: JSON.stringify(request) } }];

