};

const finalDraft = extractText(response) || previous.draft;

const materialsUsed = previous.brief.issue_materials
  .filter((material) => material.title && finalDraft.toLowerCase().includes(material.title.toLowerCase()))
  .map((material) => material.title);

return [
  {
    json: {
      status: 'completed',
      session_id: previous.brief.session_id,
      user_id: previous.brief.user_id,
      issue_number: previous.brief.issue_number,
      issue_theme: previous.brief.issue_theme,
      draft: finalDraft,
      raw_draft: previous.draft,
      column_type: previous.classification.column_type,
      secondary_type: previous.classification.secondary_type,
      confidence: previous.classification.confidence,
      classification_reason: previous.classification.reason,
      materials_used: materialsUsed,
      notes_for_editor: 'Проверь фактические упоминания материалов и финальную редакторскую интонацию перед публикацией.',
    },
  },
